script:
frappe.ui.form.on('Issue', {
    refresh: function(frm) {

        // زر لإنشاء Material Request ونسخ العناصر
        frm.add_custom_button(__('Material Request'), function() {
            frappe.model.with_doctype("Material Request", function() {
                var mr = frappe.model.get_new_doc("Material Request");

                // ربط المستند الأصلي (Issue)
                mr.issue = frm.doc.name;

                // تعبئة جدول items من issue_items
                (frm.doc.issue_items || []).forEach(function(row) {
                    var item = frappe.model.add_child(mr, "Material Request Item", "items");
                    item.item_code = row.item;
                    item.item_name = row.item_name;
                    item.uom = row.uom;
                    item.description = row.description;
                    item.qty = row.quantity;
                });

                // فتح المستند الجديد
                frappe.set_route("Form", "Material Request", mr.name);
            });
        }, __("Create"));

        // زر لإنشاء Sales Invoice ونسخ العناصر
        frm.add_custom_button(__('Sales Invoice'), function() {
            frappe.model.with_doctype("Sales Invoice", function() {
                var si = frappe.model.get_new_doc("Sales Invoice");

                // ربط المستند الأصلي (Issue)
                si.issue = frm.doc.name;

                // تعبئة جدول items من issue_items
                (frm.doc.issue_items || []).forEach(function(row) {
                    var item = frappe.model.add_child(si, "Sales Invoice Item", "items");
                    item.item_code = row.item;
                    item.item_name = row.item_name;
                    item.uom = row.uom;
                    item.description = row.description;
                    item.qty = row.quantity;
                });

                // فتح المستند الجديد
                frappe.set_route("Form", "Sales Invoice", si.name);
            });
        }, __("Create"));
    }
});




frappe.ui.form.on('Issue Items', {  // TODO:  name of child doctype
    
    item: function(frm, cdt, cdn) { // TODO:  field name at child doctype

    	var row = locals[cdt][cdn]; 
            if (row.item) {	// TODO:  field name at child doctype
                
                frappe.db.get_doc('Item', row.item)  // TODO:  Another Doctype which will get data from it  
                    .then(item => {    // name of one document
    
                        // match   name of field at table     , name of filed at another doctype  
                        frappe.model.set_value(cdt, cdn, 'item_name', item.item_name);
    
                        frappe.model.set_value(cdt, cdn, 'uom', item.stock_uom);
    
                        
    		            frappe.model.set_value(cdt, cdn, 'description', item.description);
            });
        }
    }
});
